    20→/**
    21→ *
    22→ * TODO(P1): Add implementation
    23→ *
    24→ * @brief a new ArcReplacer, with lists initialized to be empty and target size to 0
    25→ * @param num_frames the maximum number of frames the ArcReplacer will be required to cache
    26→ */
    27→ArcReplacer::ArcReplacer(size_t num_frames) : replacer_size_(num_frames) {}
    28→
    29→/**
    30→ * TODO(P1): Add implementation
    31→ *
    32→ * @brief Performs the Replace operation as described by the writeup
    33→ * that evicts from either mfu_ or mru_ into its corresponding ghost list
    34→ * according to balancing policy.
    35→ *
    36→ * If you wish to refer to the original ARC paper, please note that there are
    37→ * two changes in our implementation:
    38→ * 1. When the size of mru_ equals the target size, we don't check
    39→ * the last access as the paper did when deciding which list to evict from.
    40→ * This is fine since the original decision is stated to be arbitrary.
    41→ * 2. Entries that are not evictable are skipped. If all entries from the desired side
    42→ * (mru_ / mfu_) are pinned, we instead try victimize the other side (mfu_ / mru_),
    43→ * and move it to its corresponding ghost list (mfu_ghost_ / mru_ghost_).
    44→ *
    45→ * @return frame id of the evicted frame, or std::nullopt if cannot evict
    46→ */
    47→auto ArcReplacer::Evict() -> std::optional<frame_id_t> {
    48→  std::scoped_lock lock(latch_);
    49→
    50→  // No evictable entries
    51→  if (curr_size_ == 0) {
    52→    return std::nullopt;
    53→  }
    54→
    55→  // Helper lambda to find an evictable frame in a list
    56→  auto find_evictable_in_list = [&](std::list<frame_id_t> &list) -> std::optional<frame_id_t> {
    57→    for (auto it = list.begin(); it != list.end(); ++it) {
    58→      auto &status = alive_map_[*it];
    59→      if (status->evictable_) {
    60→        return *it;
    61→      }
    62→    }
    63→    return std::nullopt;
    64→  };
    65→
    66→  // Helper to evict from a list and move to ghost
    67→  auto evict_from_list = [&](std::list<frame_id_t> &src_list, std::list<page_id_t> &ghost_list,
    68→                              ArcStatus ghost_status, frame_id_t frame_id) {
    69→    auto status = alive_map_[frame_id];
    70→    page_id_t page_id = status->page_id_;
    71→
    72→    // Remove from source list
    73→    if (status->arc_status_ == ArcStatus::MRU) {
    74→      src_list.erase(status->mru_iter_);
    75→    } else {
    76→      src_list.erase(status->mfu_iter_);
    77→    }
    78→
    79→    // Add to ghost list (front)
    80→    ghost_list.push_front(page_id);
    81→
    82→    // Update ghost map
    83→    auto ghost_status_ptr = std::make_shared<FrameStatus>(page_id, INVALID_FRAME_ID, false, ghost_status);
    84→    ghost_status_ptr->ghost_iter_ = ghost_list.begin();
    85→    ghost_map_[page_id] = ghost_status_ptr;
    86→
    87→    // Remove from alive map
    88→    alive_map_.erase(frame_id);
    89→
    90→    // Trim ghost list if needed (should not exceed c)
    91→    while (ghost_list.size() > replacer_size_) {
    92→      auto old_page = ghost_list.back();
    93→      ghost_list.pop_back();
    94→      ghost_map_.erase(old_page);
    95→    }
    96→
    97→    curr_size_--;
    98→  };
    99→
   100→  // Decide which list to evict from based on mru_target_size_
   101→  bool evict_from_mru = (mru_.size() > mru_target_size_) || (mru_.size() == mru_target_size_ && !mru_.empty());
   102→
   103→  // If mru is empty, we must evict from mfu
   104→  if (mru_.empty()) {
   105→    evict_from_mru = false;
   106→  }
   107→  // If mfu is empty, we must evict from mru
   108→  if (mfu_.empty()) {
   109→    evict_from_mru = true;
   110→  }
   111→
   112→  // Try to evict from the preferred list first
   113→  if (evict_from_mru && !mru_.empty()) {
   114→    auto victim = find_evictable_in_list(mru_);
   115→    if (victim.has_value()) {
   116→      evict_from_list(mru_, mru_ghost_, ArcStatus::MRU_GHOST, victim.value());
   117→      return victim;
   118→    }
   119→  }
   120→
   121→  // Try to evict from mfu
   122→  if (!mfu_.empty()) {
   123→    auto victim = find_evictable_in_list(mfu_);
   124→    if (victim.has_value()) {
   125→      evict_from_list(mfu_, mfu_ghost_, ArcStatus::MFU_GHOST, victim.value());
   126→      return victim;
   127→    }
   128→  }
   129→
   130→  // If we couldn't evict from preferred list, try the other list
   131→  if (!evict_from_mru && !mru_.empty()) {
   132→    auto victim = find_evictable_in_list(mru_);
   133→    if (victim.has_value()) {
   134→      evict_from_list(mru_, mru_ghost_, ArcStatus::MRU_GHOST, victim.value());
   135→      return victim;
   136→    }
   137→  }
   138→
   139→  return std::nullopt;
   140→}
