   142→/**
   143→ * TODO(P1): Add implementation
   144→ *
   145→ * @brief Record access to a frame, adjusting ARC bookkeeping accordingly
   146→ * by bring the accessed page to the front of mfu_ if it exists in any of the lists
   147→ * or the front of mru_ if it does not.
   148→ *
   149→ * Performs the operations EXCEPT REPLACE described in original paper, which is
   150→ * handled by `Evict()`.
   151→ *
   152→ * Consider the following four cases, handle accordingly:
   153→ * 1. Access hits mru_ or mfu_
   154→ * 2/3. Access hits mru_ghost_ / mfu_ghost_
   155→ * 4. Access misses all the lists
   156→ *
   157→ * This routine performs all changes to the four lists as preperation
   158→ * for `Evict()` to simply find and evict a victim into ghost lists.
   159→ *
   160→ * Note that frame_id is used as identifier for alive pages and
   161→ * page_id is used as identifier for the ghost pages, since page_id is
   162→ * the unique identifier to the page after it's dead.
   163→ * Using page_id for alive pages should be the same since it's one to one mapping,
   164→ * but using frame_id is slightly more intuitive.
   165→ *
   166→ * @param frame_id id of frame that received a new access.
   167→ * @param page_id id of page that is mapped to the frame.
   168→ * @param access_type type of access that was received. This parameter is only needed for
   169→ * leaderboard tests.
   170→ */
   171→void ArcReplacer::RecordAccess(frame_id_t frame_id, page_id_t page_id, [[maybe_unused]] AccessType access_type) {
   172→  std::scoped_lock lock(latch_);
   173→
   174→  // Case 1: Access hits mru_ or mfu_ (alive map)
   175→  if (alive_map_.count(frame_id) > 0) {
   176→    auto status = alive_map_[frame_id];
   177→    // Move to front of mfu_ (promote to frequently used)
   178→    if (status->arc_status_ == ArcStatus::MRU) {
   179→      // Remove from mru_
   180→      mru_.erase(status->mru_iter_);
   181→      // Add to front of mfu_
   182→      mfu_.push_front(frame_id);
   183→      status->mfu_iter_ = mfu_.begin();
   184→      status->arc_status_ = ArcStatus::MFU;
   185→    } else if (status->arc_status_ == ArcStatus::MFU) {
   186→      // Already in mfu_, move to front
   187→      mfu_.erase(status->mfu_iter_);
   188→      mfu_.push_front(frame_id);
   189→      status->mfu_iter_ = mfu_.begin();
   190→    }
   191→    // Update page_id if it changed
   192→    status->page_id_ = page_id;
   193→    return;
